INSERT INTO `company_profiles` (`id`, `name`, `slogan`, `description`, `history`, `vision`, `mission`, `values`, `logo`, `logo_path`, `phone`, `email`, `address`, `instagram`, `facebook`, `twitter`, `google_map_url`, `google_map_embed`, `created_at`, `updated_at`) VALUES
(2, 'PT Sastra Bhinneka Karya', 'You Deserve The Good Service', ' PT Sastra Bhinneka Karya adalah perusahaan yang bergerak di bidang Jasa Konsultasi Konstruksi dan Non-Konstruksi. ', 'Dengan tim ahli berpengalaman, kami telah melayani berbagai perusahaan industri terkemuka di Indonesia dengan standar kualitas tertinggi dan komitmen penuh terhadap kepuasan klien.', 'Menjadi perusahaan konsultasi terkemuka yang memberikan solusi inovatif dan berkualitas tinggi di bidang konstruksi dan lingkungan untuk mendukung pembangunan berkelanjutan di Indonesia.', '[{\"item\":\"Memberikan layanan konsultasi berkualitas tinggi\"},{\"item\":\"Mengutamakan kepuasan dan kepercayaan klien\"},{\"item\":\"Menghadirkan solusi yang tepat waktu dan akurat\"},{\"item\":\"Berkontribusi pada pembangunan berkelanjutan\"}]', '[{\"icon\": \"shield\", \"title\": \"Profesional\", \"description\": \"Kami bekerja dengan standar profesionalisme tertinggi di setiap proyek\"}, {\"icon\": \"briefcase\", \"title\": \"Berpengalaman\", \"description\": \"Tim kami terdiri dari para ahli dengan pengalaman bertahun-tahun\"}, {\"icon\": \"users\", \"title\": \"Terpercaya\", \"description\": \"Rekam jejak terbukti dengan 12+ klien perusahaan besar Indonesia\"}, {\"icon\": \"bolt\", \"title\": \"Inovatif\", \"description\": \"Selalu menghadirkan solusi terbaru sesuai regulasi dan teknologi terkini\"}]', NULL, 'company/01KRBYN8RA44R2YD23R8B5DS75.png', '081312023435', 'sastrabhinneka@gmail.com', 'Jl. Merak No. 78 Sukamulya, Kab. Tangerang, Banten 15612', 'https://www.instagram.com/sastrabhinnekakarya', NULL, NULL, NULL, NULL, '2026-04-19 04:15:12', '2026-05-11 23:41:53');
