(10, 'Youssef Abdullah', 'yabdullah.agency@gmail.com', '86426769891', 'We are interested in business coperation', 'Seasons Greetings, \r\n \r\nWe are a Dubai-based business consulting and sourcing company with an extensive network of buyers, importers, distributors, and investors across the UAE and the Middle East. \r\n \r\nBased on the growing demand from our clients, we are seeking to establish business relationships with reputable manufacturers, traders, and distributors interested in expanding their products into the UAE market. \r\n \r\nThrough our network, we can introduce qualified buyers and business opportunities in sectors such as agriculture, manufacturing, construction, mining, oil and gas, consumer goods, and other industries. We conduct our business professionally and in full compliance with UAE laws and regulations. \r\n \r\nIf your company is interested in exploring cooperation opportunities, please send us your company profile, product e-catalog, and pricing information. We would be pleased to review your offerings and discuss potential business opportunities. \r\n \r\nContact me on this email address: yabdullah-agency@finvlimited.com \r\n \r\nKind regards, \r\nMr. Youssef Abdullah \r\nDubai Business Consultants', 'new', NULL, '2026-06-09 14:00:39', '2026-06-09 14:00:39'),
(11, 'Olivier G Balzac', 'oliviergabriel618@gmail.com', '87628859343', 'Please Kindly response to this important massage urgently', 'Good day, \r\n \r\nMy name is Olivier G Balzac. I previously sent you a letter regarding a transaction involving 13.5 million US dollars, which was left by my deceased client. As I have not received a response from you, I have chosen to reach out again through this platform. After reviewing your profile, I am firmly convinced that you are capable of managing this transaction alongside me very effectively. \r\n \r\nI would like to highlight that upon the successful completion of the transaction, 10% of the funds will be donated to charitable organizations, while the remaining 90% will be divided between us, resulting in an equal distribution of 45% each. \r\n \r\nPlease respond at your earliest convenience to obtain further details about the transaction. \r\n \r\nSincerely, \r\n \r\nOlivier G Balzac, \r\nAttorney. \r\nE-mail: info@balzacavocate.com \r\nWebsite: http://www.balzacavocate.com/', 'new', NULL, '2026-06-11 10:32:17', '2026-06-11 10:32:17'),
(12, 'Nik Georgios', 'nickgeorgio@protonmail.com', '88377872373', 'Private Capital to Explore', 'Dear Sir/Madam, \r\nI hope this message finds you well. \r\n \r\nMy name is Nik Georgios, and I am a private investment consultant based in the United Kingdom. I work with private investors to identify experienced business owners and fund managers who have the capability to manage capital through viable businesses and investment opportunities. \r\n \r\nI am currently working with a private investor who is seeking qualified business owners and fund managers with the capacity to manage substantial investment capital. \r\n \r\nIf you are interested in exploring this opportunity, please reply to this email, and I will be pleased to provide you with further details and discuss the next steps. \r\n \r\nKindly send your reply to: nickgeorgio@mail.com \r\n \r\nI look forward to hearing from you. \r\n \r\nKind regards, \r\n \r\nNik Georgios', 'new', NULL, '2026-07-07 13:16:24', '2026-07-07 13:16:24'),
(13, 'erdqhllikt', 'lkhizxls@immenseignite.info', '+1-579-367-9790', 'yttodpnvhw', 'ioroqtwtkkiofvudlyhhhmoewgywvh', 'new', NULL, '2026-07-07 15:19:04', '2026-07-07 15:19:04'),
(14, 'mrsvrnnmdi', 'qnlnlghm@immenseignite.info', '+1-500-284-9149', 'gigoogfjkn', 'yfljqgusifteuswfmsdtwzjflwsstt', 'new', NULL, '2026-07-07 15:19:10', '2026-07-07 15:19:10');
