INSERT INTO `portfolios` (`id`, `client_id`, `document_name`, `document_category`, `month`, `year`, `description`, `is_visible`, `sort_order`, `created_at`, `updated_at`) VALUES
(1, 9, 'VERIFIKASI LAPANGAN', 'Konstruksi', 1, '2026', 'Didukung oleh tim profesional, kami selalu mengutamakan kenyamanan dan keamanan pelanggan. Kami berusaha menciptakan pengalaman peminjaman yang cepat, aman, dan terpercaya, sehingga pelanggan tidak perlu khawatir mengenai kualitas atau kondisi barang.', 1, 0, '2026-04-11 14:42:05', '2026-04-11 14:42:05'),
(2, 9, 'VERLAP IPAL', 'Konstruksi', 1, '2026', 'As a state-owned company whose shares are 100% owned by the Indonesian government, Pertamina always maintains corporate accountability by providing accurate information.', 1, 0, '2026-04-12 03:26:33', '2026-04-12 03:26:33'),
(3, 10, 'VERIFIKASI LAPANGAN', 'Konstruksi', 2, '2026', 'Didukung oleh tim profesional, kami selalu mengutamakan kenyamanan dan keamanan pelanggan. Kami berusaha menciptakan pengalaman peminjaman yang cepat, aman, dan terpercaya, sehingga pelanggan tidak perlu khawatir mengenai kualitas atau kondisi barang.', 1, 0, '2026-04-12 03:29:33', '2026-04-12 03:29:33'),
(7, 19, 'Komisioning Instalasi Pengolahan Air Limbah (IPAL)', 'Konstruksi', 5, '2026', 'Dokumen lingkungan adalah dokumen yang wajib dimiliki bagi pelaku usaha/kegiatan yang memuat upaya pengelolaan dan pemantauan lingkungan atas dampak yang ditimbulkan, sebagai dasar penerbitan perizinan berusaha sesuai dengan Undang-Undang No. 32 Tahun 2009 tentang Perlindungan dan Pengelolaan Lingkungan Hidup, Peraturan Pemerintah No. 22 Tahun 2021 tentang Penyelenggaraan Perlindungan dan Pengelolaan Lingkungan Hidup', 1, 0, '2026-05-06 17:16:08', '2026-05-06 17:16:08'),
(8, 27, 'Konsultasi Publik AMDAL (Analisis Dampak Lingkungan)', 'Lingkungan, Konstruksi ', 5, '2026', 'Konsultasi Publik AMDAL \nKonsultasi publik AMDAL (Analisis Mengenai Dampak Lingkungan) adalah tahapan wajib di mana pemrakarsa usaha menyampaikan rencana proyek dan menampung saran/tanggapan masyarakat terdampak langsung, sesuai PP No. 22 Tahun 2021. Proses ini memastikan transparansi dan mengakomodasi aspirasi masyarakat untuk memitigasi risiko lingkungan. Kegiatan ini juga diawasi oleh Tim Konsultan dan Tenaga Ahli yang sudah mahir dibidangnya.', 1, 0, '2026-05-13 09:23:01', '2026-06-23 08:49:35'),
(9, 11, 'Verlap SLO Emisi Udara (Surat Kelayakan Operasional)', 'Lingkungan', 2, '2026', 'Verifikasi Lapangan (Verlap) untuk Surat Kelayakan Operasional (SLO) Emisi Udara adalah proses pemeriksaan fisik langsung oleh instansi lingkungan hidup (DLH/KLHK) dan Tim Konsultan Serta Tenaga Ahli yang Profesional  ke lokasi kegiatan usaha. Tujuannya untuk memastikan bahwa alat pengendali emisi yang terpasang telah sesuai dengan Persetujuan Teknis (Pertek) dan memenuhi baku mutu emisi yang ditetapkan', 1, 0, '2026-05-13 10:19:18', '2026-05-25 09:57:03'),
(10, 11, 'Verlap Rintek Limbah B3', 'Lingkungan,Konstruksi', 9, '2025', 'Verlap (Verifikasi Lapangan) Rintek (Rincian Teknis) Limbah B3 adalah proses peninjauan lapangan oleh Dinas Lingkungan Hidup (DLH) untuk memastikan kesesuaian sarana penyimpanan sementara limbah B3 di lokasi industri dengan dokumen teknis yang diajukan. Proses ini merupakan bagian dari pengurusan Persetujuan Lingkungan/Persetujuan Teknis (Pertek) sesuai PP No 22 Tahun 2021, menggantikan mekanisme izin TPS lama.', 1, 0, '2026-05-13 10:22:14', '2026-05-13 10:22:14'),
(11, 28, 'Verlap Rintek Limbah B3', 'Lingkungan', 6, '2025', 'Verlap (Verifikasi Lapangan) Rintek (Rincian Teknis) Limbah B3 adalah proses peninjauan lapangan oleh Dinas Lingkungan Hidup (DLH) untuk memastikan kesesuaian sarana penyimpanan sementara limbah B3 di lokasi industri dengan dokumen teknis yang diajukan. Proses ini merupakan bagian dari pengurusan Persetujuan Lingkungan/Persetujuan Teknis (Pertek) sesuai PP No 22 Tahun 2021, menggantikan mekanisme izin TPS lama. Diawasi Langsung oleh Tim ahli dan konsultan yang berpengalaman\n', 1, 0, '2026-05-13 10:28:37', '2026-05-25 14:25:59'),
(12, 29, 'SLF (Sertifkat Laik Fungsi)', 'Lingkungan,Konstruksi', 5, '2026', '\"Verifikasi Lapangan SLF\" (Sertifikat Laik Fungsi) adalah tahapan inspeksi fisik oleh tim penilik/teknis daerah untuk memastikan kesesuaian bangunan dengan dokumen PBG. yang diawasli langsung oleh Tim Ahli dan Konsutan yang sudah berpengalaman', 1, 0, '2026-05-21 09:12:02', '2026-05-25 14:27:15');
INSERT INTO `services` (`id`, `title`, `category`, `description`, `icon`, `image_path`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES
(25, 'Jasa Perencanaan & Pembangunan IPAL/WWTP/STP', 'construction', '<p>Layanan menyeluruh mulai dari desain rekayasa hingga pembangunan sistem pengolahan air limbah domestik maupun industri.</p><ul><li><p><strong>Keunggulan:</strong> Desain sistem yang efisien energi dan lahan.</p></li><li><p><strong>Output:</strong> Instalasi pengolahan limbah yang memenuhi baku mutu pemerintah.</p></li><li><p><strong>Teknologi:</strong> Menggunakan teknologi <em>Biological Treatment</em>, <em>Physical-Chemical</em>, hingga <em>Advanced Oxidation</em>.</p></li></ul>', NULL, 'services/01KPKJFQZ9B8PP9CVXZVGFF5E0.jpg', 0, 1, '2026-04-12 08:00:19', '2026-04-20 01:43:05'),
(33, 'Jasa Perencanaan Wilayah/Tapak', 'construction', '<p>Penyusunan rencana tata ruang dan tata guna lahan yang optimal untuk pengembangan kawasan industri, perumahan, maupun komersial.</p><ul><li><p>Analisis daya dukung lingkungan.</p></li><li><p>Perencanaan zonasi dan infrastruktur dasar.</p></li><li><p>Integrasi konsep <em>Green Development</em> pada desain tapak.</p></li></ul>', NULL, 'services/01KPKJQ0089W95HFVCTA4JKRVW.jpg', 0, 1, '2026-04-19 19:15:39', '2026-04-19 19:16:05'),
(34, 'Jasa Pengujian Laik Bangunan/Gedung', 'construction', '<p>Audit teknis struktur dan fasilitas gedung untuk memastikan keamanan fungsional bangunan sebelum digunakan.</p><ul><li><p>Pemeriksaan struktur (beton, baja, pondasi).</p></li><li><p>Pengujian sistem ME (Mekanikal Elektrikal) dan proteksi kebakaran.</p></li><li><p>Prasyarat utama untuk penerbitan Sertifikat Laik Fungsi (SLF).</p></li></ul>', NULL, 'services/01KPKK0GQRZ3NA3PXMQ8VSAZ5N.jpg', 0, 1, '2026-04-19 19:20:51', '2026-04-19 19:20:51'),
(36, 'Jasa Pengujian Air Bersih (Geolistrik)', 'construction', '<p>Pendugaan lapisan akuifer tanah untuk menentukan titik pengeboran air tanah yang potensial dan berkualitas.</p><ul><li><p>Pemetaan potensi air tanah menggunakan metode geofisika.</p></li><li><p>Analisis kedalaman dan ketebalan lapisan pembawa air.</p></li><li><p>Minimalisir risiko kegagalan pengeboran air sumur dalam.</p></li></ul>', NULL, 'services/01KPKKV1TTDEPHC7TVFK4N25JH.jpg', 0, 1, '2026-04-19 19:35:20', '2026-04-19 19:36:15'),
(37, 'Jasa Pengujian Air Limbah (Laboratorium)', 'construction', '<p>Analisis parameter kimia, fisika, dan biologi pada air limbah hasil olahan melalui laboratorium terakreditasi.</p><ul><li><p>Pengujian BOD, COD, TSS, hingga logam berat.</p></li><li><p>Laporan analisis sesuai standar Baku Mutu Lingkungan.</p></li><li><p>Rekomendasi perbaikan sistem jika hasil melebihi ambang batas.</p></li></ul>', NULL, 'services/01KPKKZ7BMAMWMPN921T6JT9ZY.jpg', 0, 1, '2026-04-19 19:37:37', '2026-04-19 19:37:46'),
(38, 'Jasa Konstruksi Gedung', 'construction', '<p>Pelaksanaan pembangunan fisik gedung perkantoran, pabrik, gudang, maupun hunian dengan standar mutu tinggi.</p><ul><li><p>Manajemen proyek konstruksi yang sistematis.</p></li><li><p>Pengawasan ketat terhadap K3 (Kesehatan dan Keselamatan Kerja).</p></li><li><p>Pengerjaan tepat waktu dengan hasil struktur yang presisi.</p></li></ul>', NULL, 'services/01KPKM0VSNFVNHRXSJJ2C28VDQ.jpg', 0, 1, '2026-04-19 19:38:31', '2026-04-19 19:38:31'),
(39, 'Jasa Pemasangan Electrical', 'construction', '<p>Instalasi sistem kelistrikan bangunan skala menengah hingga besar yang aman dan sesuai standar SNI/PUIL.</p><ul><li><p>Pemasangan panel distribusi listrik dan trafo.</p></li><li><p>Instalasi sistem pencahayaan dan titik daya.</p></li><li><p>Pemasangan sistem grounding dan proteksi petir.</p></li></ul>', NULL, 'services/01KPKM4QCQ9ZWDH6N7T9T4APGS.jpg', 0, 1, '2026-04-19 19:40:37', '2026-04-19 19:40:37'),
(40, 'Jasa Penyusunan Dokumen Lingkungan (UKL-UPL)', 'non-construction', '<p>Penyusunan dokumen pengelolaan dan pemantauan lingkungan bagi rencana usaha yang tidak berdampak penting bagi lingkungan.</p><ul><li><p>Identifikasi dampak operasional usaha terhadap lingkungan.</p></li><li><p>Penyusunan rencana pengelolaan (RKL) dan pemantauan (RPL).</p></li><li><p>Pendampingan proses pengesahan di instansi terkait.</p></li></ul>', NULL, 'services/01KPKM5ZTBTGCRMNEAJN1TXMNV.jpg', 0, 1, '2026-04-19 19:41:19', '2026-04-19 19:41:19'),
(41, 'Dokumen AMDAL/ANDAL', 'non-construction', '<p>Kajian mendalam mengenai dampak besar dan penting suatu usaha/kegiatan terhadap lingkungan hidup.</p><ul><li><p>Kajian aspek abiotik, biotik, dan kultural.</p></li><li><p>Penyusunan Kerangka Acuan (KA), ANDAL, RKL, dan RPL.</p></li><li><p>Diperuntukkan bagi proyek skala besar atau industri berisiko tinggi.</p></li></ul>', NULL, 'services/01KPM5PN553RGWACYXG4H8TVQX.jpg', 0, 1, '2026-04-20 00:47:30', '2026-04-20 00:47:30'),
(42, 'Dokumen Persetujuan Teknis (Air & Udara)', 'non-construction', '<p>Penyusunan kajian teknis sebagai syarat pemenuhan baku mutu pembuangan limbah ke media lingkungan.</p><ul><li><p>Pertek BMAL (Baku Mutu Air Limbah).</p></li><li><p>Pertek Emisi Udara untuk cerobong industri.</p></li><li><p>Kajian dispersi dan pemodelan dampak lingkungan.</p></li></ul>', NULL, 'services/01KPM5SY90N0Z98A5JCXC18S7H.jpg', 0, 1, '2026-04-20 00:49:18', '2026-04-20 00:49:18'),
(43, 'Dokumen Rincian Pengelolaan Limbah B3', 'non-construction', '<p>Perencanaan prosedur penyimpanan, pengumpulan, dan pengelolaan limbah Bahan Berbahaya dan Beracun (B3).</p><ul><li><p>Standarisasi simbol dan label limbah B3.</p></li><li><p>Desain tempat penyimpanan sementara (TPS) limbah B3 sesuai regulasi.</p></li><li><p>Penyusunan logbook dan neraca limbah B3.</p></li></ul>', NULL, 'services/01KPM5W7JPQRFKD1AYR9G3G2E8.jpg', 0, 1, '2026-04-20 00:50:33', '2026-04-20 00:50:33'),
(44, 'Dokumen Analisa Dampak Lalu Lintas (Andalalin)', 'non-construction', '<p>Studi teknis mengenai dampak lalu lintas yang ditimbulkan oleh pembangunan pusat kegiatan atau pemukiman.</p><ul><li><p>Analisis tarikan dan bangkitan lalu lintas.</p></li><li><p>Rekomendasi manajemen dan rekayasa lalu lintas sekitar area.</p></li><li><p>Mitigasi kemacetan akibat operasional bangunan.</p></li></ul>', NULL, 'services/01KPM5XFJG8ZRE66WC7TFCK975.jpg', 0, 1, '2026-04-20 00:51:14', '2026-04-20 00:51:14'),
(45, 'Jasa Pengurusan PBG & SLF', 'non-construction', '<p>Bantuan legalitas untuk mendapatkan Persetujuan Bangunan Gedung (PBG) dan Sertifikat Laik Fungsi (SLF).</p><ul><li><p>Input data teknis pada sistem SIMBG.</p></li><li><p>Koordinasi dengan Tim Profesi Ahli (TPA) pemerintah.</p></li><li><p>Pemenuhan standar teknis gedung secara administratif.</p></li></ul>', NULL, 'services/01KPM614F1S9VS1QMD2HH8ED15.jpg', 0, 1, '2026-04-20 00:53:14', '2026-04-20 00:53:14'),
(46, 'Jasa Pengurusan Siteplan', 'non-construction', '<p>Penyusunan dan pengesahan gambar rencana tapak bangunan di dinas perizinan daerah.</p><ul><li><p>Penentuan GSB (Garis Sempadan Bangunan).</p></li><li><p>Proporsi Ruang Terbuka Hijau (RTH) dan fasilitas umum.</p></li><li><p>Legalitas awal sebelum proses pecah sertifikat atau pembangunan.</p></li></ul>', NULL, 'services/01KPM62RQH8NNSFTFKBEX7Y54F.jpg', 0, 1, '2026-04-20 00:54:07', '2026-04-20 00:54:07'),
(47, 'Jasa Legalitas & Perpajakan', 'non-construction', '<p>Pendampingan pendirian badan usaha dan pengelolaan kepatuhan pajak perusahaan secara profesional.</p><ul><li><p>Pembuatan Akta Notaris, NIB, hingga Izin Usaha.</p></li><li><p>Laporan SPT Masa dan Tahunan.</p></li><li><p>Audit internal dan perencanaan pajak (Tax Planning).</p></li></ul>', NULL, 'services/01KPM7CXTJK4ZN8DJG7ZWM6NRR.jpg', 0, 1, '2026-04-20 01:17:09', '2026-04-20 01:17:09'),
(48, 'Jasa Desain Interior & Eksterior', 'non-construction', '<p>Layanan desain estetika ruang yang menggabungkan kenyamanan fungsional dengan identitas visual perusahaan.</p><ul><li><p>Visualisasi 3D berkualitas tinggi.</p></li><li><p>Pemilihan material yang awet dan efisien biaya.</p></li><li><p>Konsep desain modern, minimalis, maupun industrial.</p></li></ul>', NULL, 'services/01KPM7KR1BA5Y25QBYHZ3JY6ZT.jpg', 0, 1, '2026-04-20 01:20:52', '2026-04-20 01:20:52'),
(49, 'Jasa Desain Arsitektur & MEP', 'non-construction', '<p>Penyusunan gambar teknis bangunan lengkap (DED) yang mencakup arsitektur, mekanikal, elektrikal, dan plumbing.</p><ul><li><p>Gambar denah, tampak, potongan, dan detail arsitektur.</p></li><li><p>Rancangan jaringan distribusi air bersih dan air kotor.</p></li><li><p>Perhitungan beban listrik dan titik lampu.</p></li></ul>', NULL, 'services/01KPM7SNJWHAR343DJC1EEB351.jpg', 0, 1, '2026-04-20 01:24:06', '2026-04-20 01:24:06'),
(50, 'Jasa Perencanaan WWTP/STP', 'non-construction', '<p>Kajian teknis awal (Feasibility Study) untuk sistem pengolahan limbah cair sebelum masuk ke tahap pembangunan.</p><ul><li><p>Analisis debit dan karakteristik limbah cair.</p></li><li><p>Pemilihan metode pengolahan yang paling hemat biaya (Cost-effective).</p></li><li><p>Perhitungan Rencana Anggaran Biaya (RAB) pembangunan.</p></li></ul>', NULL, 'services/01KPM7Y6JW352657M4GY171JWA.jpg', 0, 1, '2026-04-20 01:26:35', '2026-04-20 01:27:04'),
(51, 'Jasa Pengurusan SIPA', 'non-construction', '<p>Pendampingan perizinan Surat Izin Pengambilan Air Tanah (SIPA) bagi pelaku industri maupun komersial.</p><ul><li><p>Koordinasi dengan Dinas ESDM terkait titik bor.</p></li><li><p>Pemasangan meter air dan pengurusan dokumen teknis.</p></li><li><p>Pemantauan kualitas dan kuantitas penggunaan air tanah.</p></li></ul>', NULL, 'services/01KPM83Q7X5Y1EDFT0MRPDPYFN.jpg', 0, 1, '2026-04-20 01:29:36', '2026-04-20 01:29:36'),
(52, 'Jasa Perencanaan Database Web/Aplikasi', 'non-construction', '<p>Solusi teknologi informasi untuk manajemen data perusahaan yang aman, cepat, dan terstruktur.</p><ul><li><p>Desain arsitektur database (SQL/NoSQL).</p></li><li><p>Integrasi data antar sistem perusahaan.</p></li><li><p>Optimasi performa dan keamanan data dari akses ilegal.</p></li></ul>', NULL, 'services/01KPM8G4CADHDYBZ1H6BRKAB5R.jpg', 0, 1, '2026-04-20 01:36:22', '2026-04-20 01:36:22'),
(53, 'Jasa Pemetaan Wilayah & Geologi', 'non-construction', '<p>Pengambilan data spasial dan analisis lapisan bumi untuk kebutuhan survei lahan maupun eksplorasi.</p><ul><li><p>Pemetaan menggunakan Drone (UAV) atau total station.</p></li><li><p>Analisis topografi dan kontur tanah.</p></li><li><p>Investigasi geologi untuk stabilitas lereng atau pondasi berat.</p></li></ul>', 'fa fa-home', 'services/01KPM8NDQ4BRZWKQN4VR9WWG98.jpg', 0, 1, '2026-04-20 01:39:16', '2026-05-05 08:32:10');
