INSERT INTO `testimonials` (`id`, `client_name`, `position`, `company`, `content`, `rating`, `photo`, `is_visible`, `sort_order`, `created_at`, `updated_at`) VALUES
(4, 'Bambang Setiadi', 'Project Manager', 'PT Perkasa Alam Rekayasa', 'Kerjasama dengan PT Sastra Bhinneka Karya sangat memuaskan. Ketepatan waktu dan detail pengerjaan dalam konsultasi teknis yang diberikan sangat membantu kelancaran proyek infrastruktur kami. Sangat direkomendasikan bagi yang mencari mitra konstruksi yang andal.', 5, 'testimonials/photos/01KQ8ZX6PQGZAJDAVZZEZYNBMK.png', 1, 1, '2026-04-19 16:32:56', '2026-05-06 16:00:48'),
(5, 'Sarah Amalia, M.T.', 'Direktur Operasional', 'CV Sinergi Muda Tangerang', 'Timnya sangat responsif dan solutif dalam memberikan saran teknis. Mereka tidak hanya memberikan jasa, tetapi juga edukasi yang mendalam terkait standar keamanan bangunan terbaru. Benar-benar profesional di bidangnya!', 5, NULL, 1, 0, '2026-04-19 16:33:37', '2026-04-19 16:33:37'),
(6, 'Hendra Kusuma', 'Owner', 'Sentra Distribusi Nusantara', 'Awalnya ragu mencari konsultan yang tepat, namun Sastra Bhinneka Karya membuktikan integritas mereka melalui hasil kerja yang transparan dan akurat. Proses birokrasi dan perizinan jadi jauh lebih mudah berkat arahan mereka. Sukses selalu!', 5, NULL, 1, 0, '2026-04-19 16:33:54', '2026-04-19 16:33:54');
