DROP TABLE IF EXISTS `homepage_settings`;
CREATE TABLE `homepage_settings` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `hero_background_image` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Path gambar background hero (grayscale + gelap)',
  `hero_logo_image` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `hero_badge_text` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Jasa Konsultasi & Konstruksi' COMMENT 'Teks badge kecil di atas judul',
  `hero_title_line1` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'SASTRA',
  `hero_title_line2` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'BHINNEKA',
  `hero_title_line3` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'KARYA',
  `hero_tagline` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'You Deserve The Good Service' COMMENT 'Kalimat italic di bawah judul',
  `hero_description` text COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Solusi terpercaya untuk kebutuhan jasa konsultasi konstruksi, lingkungan, dan perizinan. Berpengalaman melayani industri terkemuka di Indonesia.' COMMENT 'Paragraf deskripsi hero',
  `hero_btn_primary_text` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Lihat Layanan',
  `hero_btn_secondary_text` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Hubungi Kami',
  `hero_whatsapp_number` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '6281312023435',
  `hero_whatsapp_message` text COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Halo Sastra Bhinneka Karya, saya ingin konsultasi lebih lanjut.',
  `stat_clients` smallint(5) unsigned NOT NULL DEFAULT 10 COMMENT 'Jumlah klien aktif',
  `stat_projects` smallint(5) unsigned NOT NULL DEFAULT 50 COMMENT 'Jumlah proyek selesai',
  `stat_services` smallint(5) unsigned NOT NULL DEFAULT 23 COMMENT 'Jumlah jenis layanan',
  `stat_years` smallint(5) unsigned NOT NULL DEFAULT 5 COMMENT 'Tahun pengalaman',
  `stat_clients_label` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Klien Aktif',
  `stat_projects_label` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Proyek Selesai',
  `stat_services_label` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Jenis Layanan',
  `stat_years_label` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Tahun Pengalaman',
  `about_image` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Foto tim / proyek di section about',
  `about_section_tag` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Tentang Kami',
  `about_title` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Solusi Terbaik untuk Bisnis Anda',
  `about_description` text COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'PT Sastra Bhinneka Karya adalah perusahaan jasa konsultasi berpengalaman di bidang konstruksi dan non-konstruksi. Kami hadir memberikan solusi terbaik bagi perusahaan Anda dalam menghadapi tantangan regulasi, lingkungan, dan infrastruktur.',
  `about_highlights` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL DEFAULT '["Tim Ahli Berpengalaman","Solusi Terintegrasi","Tepat Waktu & Akurat","Harga Kompetitif"]' COMMENT 'Array JSON 4 poin keunggulan',
  `cta_section_tag` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Mulai Sekarang',
  `cta_title` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Siap Bekerja Sama dengan Kami?',
  `cta_title_highlight` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'dengan Kami?' COMMENT 'Bagian judul CTA yang berwarna merah',
  `cta_description` text COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Konsultasikan kebutuhan bisnis Anda bersama tim ahli kami. Kami siap memberikan solusi terbaik.',
  `cta_btn_text` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Hubungi Kami Sekarang',
  `contact_address` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Jl. Merak No. 78 Sukamulya, Tangerang',
  `contact_phone` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '081312023435',
  `contact_email` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'sastrabhinekakarya@gmail.com',
  `contact_maps_embed_url` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'https://maps.google.com/maps?q=Jl.+Merak+No.78+Sukamulya+Tangerang&output=embed' COMMENT 'URL iframe Google Maps',
  `meta_title` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Beranda',
  `meta_description` text COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'PT Sastra Bhinneka Karya melayani jasa konsultasi konstruksi, lingkungan, perizinan, dokumen teknis, serta kebutuhan industri di Indonesia.',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

